#include <stdio.h>
int popcount_naive(unsigned int n) {
    int count = 0;
    while (n) { count += n & 1; n >>= 1; }
    return count;
}
int popcount_kernighan(unsigned int n) {
    int count = 0;
    while (n) { count++; n &= n - 1; }
    return count;
}
int main(void) {
    unsigned int v = 0xDEADBEEF;
    printf("0xDEADBEEF naive    : %d\n", popcount_naive(v));
    printf("0xDEADBEEF kernighan: %d\n", popcount_kernighan(v));
    printf("0x00000000 naive    : %d\n", popcount_naive(0));
    printf("0xFFFFFFFF kernighan: %d\n", popcount_kernighan(0xFFFFFFFF));
    return 0;
}

