/* == EXEMPLE ================================================
 * Compter les zeros de tete (count leading zeros)
 * Meme principe : boucle bit-a-bit avec masque et decalage
 * =========================================================== */
int example_clz(unsigned int n) {
    if (n == 0) return 32;
    int count = 0;
    unsigned int mask = 1u << 31;  /* bit de poids fort */
    while ((n & mask) == 0) {
        count++;
        mask >>= 1;
    }
    return count;
}
int example_ctz(unsigned int n) {
    if (n == 0) return 32;
    int count = 0;
    while ((n & 1) == 0) {  /* teste le bit de poids faible */
        count++;
        n >>= 1;
    }
    return count;
}
